const parts = [$.input.keyword];
const staticTerms = "{{}} best guide comprehensive";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const results = $.steps.keywordResearch.response.results || [];
let researchText = '';
results.forEach((r, i) => {
  researchText += (i+1) + '. ' + (r.title || 'Untitled') + '\n';
  researchText += '   URL: ' + r.url + '\n';
  if (r.highlights && r.highlights.length > 0) {
    researchText += '   Key points: ' + r.highlights.join(' | ') + '\n';
  }
  researchText += '   Content: ' + (r.text || '').slice(0, 800) + '\n\n';
});
return { researchText, sourceCount: results.length };

const keyword = $.input.keyword;
const tone = $.input.tone || 'professional';
const wordCount = $.input.wordCount || 1500;
const research = $.steps.compileResearch.output.researchText;

const prompt = `You are an expert SEO content writer. Write a comprehensive, SEO-optimized blog post based on the following keyword and research.

TARGET KEYWORD: ${keyword}
TONE: ${tone}
TARGET WORD COUNT: ${wordCount}

COMPETITOR RESEARCH (${$.steps.compileResearch.output.sourceCount} top-ranking pages analyzed):
${research}

INSTRUCTIONS:
- Write an engaging, original article that outperforms the competition
- Include the target keyword naturally in the title, first paragraph, headings, and throughout
- Use proper HTML heading tags (h2, h3) for structure
- Write the content body in HTML (paragraphs with <p>, lists with <ul>/<ol>, bold with <strong>)
- Include a compelling introduction and conclusion
- Add internal linking suggestions where relevant
- Optimize for featured snippets where possible

Return ONLY valid JSON:
{
  "title": "<SEO-optimized title with keyword>",
  "slug": "<url-friendly-slug>",
  "metaDescription": "<155 char meta description with keyword>",
  "content": "<full HTML article body>",
  "tags": ["<tag1>", "<tag2>", "<tag3>"],
  "categories": ["<category1>"],
  "excerpt": "<2-3 sentence excerpt>",
  "estimatedWordCount": ${wordCount},
  "keywordDensity": "<percentage>"
}`;
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.keyword + ' - Complete Guide', slug: $.input.keyword.toLowerCase().replace(/[^a-z0-9]+/g, '-'), metaDescription: 'A comprehensive guide about ' + $.input.keyword, content: '<p>' + raw + '</p>', tags: [$.input.keyword], categories: ['Blog'], excerpt: 'A guide about ' + $.input.keyword }; }
